#[rustfmt::skip]
const B3: [f32; 5] = [-0.220450, 0.194716, 0.461845, -0.200657, -0.372752];

const CLASS_NAMES: [&str; 5] = ["absent", "present_still", "present_moving", "active", "lying_still"];

pub fn classify(features: &[f32; 27]) -> (usize, f32, &'static str) {
    let mut x = [0.0f32; 27];
    for i in 0..27 { x[i] = (features[i] - NORM_MEAN[i]) / NORM_STD[i]; }
    let mut h0 = [0.0f32; 128];
    for j in 0..128 { let mut s = B0[j]; for i in 0..27 { s += x[i] * W0[i][j]; } h0[j] = if s > 0.0 { s } else { 0.0 }; }
    let mut h1 = [0.0f32; 64];
    for j in 0..64 { let mut s = B1[j]; for i in 0..128 { s += h0[i] * W1[i][j]; } h1[j] = if s > 0.0 { s } else { 0.0 }; }
    let mut h2 = [0.0f32; 32];
    for j in 0..32 { let mut s = B2[j]; for i in 0..64 { s += h1[i] * W2[i][j]; } h2[j] = if s > 0.0 { s } else { 0.0 }; }
    let mut logits = [0.0f32; 5];
    for j in 0..5 { let mut s = B3[j]; for i in 0..32 { s += h2[i] * W3[i][j]; } logits[j] = s; }
    let max_l = logits.iter().cloned().fold(f32::NEG_INFINITY, f32::max);
    let mut exp_sum = 0.0f32;
    let mut probs = [0.0f32; 5];
    for j in 0..5 { probs[j] = (logits[j] - max_l).exp(); exp_sum += probs[j]; }
    for j in 0..5 { probs[j] /= exp_sum; }
    let mut best = 0;
    for j in 1..5 { if probs[j] > probs[best] { best = j; } }
    (best, probs[best], CLASS_NAMES[best])
}
